import anthropic, json

client = anthropic.Anthropic()

SESSION_PLAN_TOOL = {
    "name": "create_session_plan",
    "description": "Create a prototype testing session plan.",
    "input_schema": {
        "type": "object",
        "properties": {
            "session_id":         {"type": "string"},
            "participant_profile":{"type": "string"},
            "tasks": {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "task_id":      {"type": "string"},
                        "scenario":     {"type": "string"},
                        "prompt_text":  {"type": "string"},
                        "success_criteria": {"type": "array", "items": {"type": "string"}},
                        "must_not_trigger": {"type": "array", "items": {"type": "string"}}
                    },
                    "required": ["task_id","scenario","prompt_text","success_criteria","must_not_trigger"]
                }
            },
            "interview_questions":{
                "type": "array",
                "items": {"type": "string"}
            },
            "observation_focus":  {"type": "array", "items": {"type": "string"}}
        },
        "required": ["session_id","participant_profile","tasks","interview_questions","observation_focus"]
    }
}

def generate_session_plan(
    feature_description: str,
    persona_brief: str,
    prototype_a_prompt: str,
    prototype_b_prompt: str,
    must_do: list[str],
    must_not_do: list[str]
) -> dict:
    """
    Generate a 90-minute usability testing session plan for two prompt prototypes.
    Tasks are derived from the behaviour spec must/must-not items.
    """
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=2000,
        tools=[SESSION_PLAN_TOOL],
        tool_choice={"type": "any"},
        system=(
            "You are a UX researcher designing a usability test for a Claude-powered feature. "
            "Create tasks that exercise the must_do and must_not_do items from the behaviour spec. "
            "Each task must have a concrete scenario, a participant prompt, success criteria, "
            "and behaviours that must NOT be triggered during the task."
        ),
        messages=[{
            "role": "user",
            "content": (
                f"Feature: {feature_description}\n"
                f"Persona: {persona_brief}\n"
                f"Prototype A system prompt (first 200 chars): {prototype_a_prompt[:200]}...\n"
                f"Prototype B system prompt (first 200 chars): {prototype_b_prompt[:200]}...\n"
                f"Must Do: {must_do}\n"
                f"Must Not Do: {must_not_do}\n\n"
                "Create a session plan with 4–5 tasks covering: happy path, boundary, negative, and recovery."
            )
        }]
    )
    for block in response.content:
        if block.type == "tool_use" and block.name == "create_session_plan":
            return block.input
    return {}

import anthropic, json

client = anthropic.Anthropic()

PROMPT_REVISION_TOOL = {
    "name": "propose_prompt_revision",
    "description": "Propose a specific revision to a system prompt based on a testing insight.",
    "input_schema": {
        "type": "object",
        "properties": {
            "insight_id":      {"type": "string"},
            "original_clause": {"type": ["string","null"]},
            "revised_clause":  {"type": "string"},
            "rationale":       {"type": "string"},
            "test_to_verify":  {"type": "string"}
        },
        "required": ["insight_id","revised_clause","rationale","test_to_verify"]
    }
}

def derive_prompt_revisions(
    current_prompt: str,
    insights: list[dict]
) -> list[dict]:
    """
    For each insight that requires a prompt update, propose the specific
    clause to add, remove, or rewrite — not a generic recommendation.
    """
    update_insights = [i for i in insights if i["action"] == "update_prompt"]
    if not update_insights:
        return []

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=2000,
        tools=[PROMPT_REVISION_TOOL],
        tool_choice={"type": "auto"},
        messages=[{
            "role": "user",
            "content": (
                f"Current system prompt:\n{current_prompt}\n\n"
                "Insights requiring prompt updates:\n"
                + json.dumps(update_insights, indent=2) + "\n\n"
                "For each insight, call propose_prompt_revision with the SPECIFIC clause to change "
                "(quote the original clause if modifying; write the new clause in full). "
                "Include a one-sentence test that verifies the revision worked."
            )
        }]
    )
    return [b.input for b in response.content if b.type == "tool_use" and b.name == "propose_prompt_revision"]
